import React from 'react'
import { useCountdownStore } from './useCountDownStore'
import useCountdown from './useCountdown'

export function TimeInputs() {
    const { timeInput, setTimeInput } = useCountdownStore((state) => state)
    const handleChange = (value, key) => {
        setTimeInput({ ...timeInput, [key]: value })
    }
    return (<>
        <input type='number' onChange={(e) => handleChange(e.target.value, 'hours')} value={timeInput.hours} placeholder='HH' />
        <input type='number' onChange={(e) => handleChange(e.target.value, 'minutes')} value={timeInput.minutes} placeholder='mm' />
        <input type='number' onChange={(e) => handleChange(e.target.value, 'seconds')} value={timeInput.seconds} placeholder='ss' />
    </>)
}

export function TimeDisplay() {
    const { timeLeft } = useCountdownStore((state) => state)
    console.log('timeLeft>>>', timeLeft)
    function formatTime() {
        const hrs = String(Math.floor(timeLeft / 3600)).padStart(2, '0')
        const mins = String(Math.floor((timeLeft % 3600) / 60)).padStart(2, '0')
        const secs = String(Math.floor(timeLeft % 60)).padStart(2, '0')
        return `${hrs}:${mins}:${secs}`
    }
    return (
        <h1>{formatTime()}</h1>
    )
}

export function Controls() {
    const state = useCountdownStore((state) => state)
    const isRunning = state.isRunning
    const { start, pause, reset } = useCountdown()
    return (
        <div>
            <button disabled={isRunning} onClick={start}>
                Start
            </button>
            <button disabled={!isRunning} onClick={pause}>
                Pause
            </button>
            <button onClick={reset}>
                Reset
            </button>
        </div>
    )
}
function CountdownTimer() {
    return (
        <div className='countdown'>
            <TimeInputs />
            <TimeDisplay />
            <Controls />
        </div>
    )
}

export default CountdownTimer
